import { GoogleGenAI, Chat } from "@google/genai";
// Fix: Removed unused and non-existent import 'LISTING_LIMITS' from "../constants"
// import { COMMISSIONS, LISTING_LIMITS } from "../constants";

let chatSession: Chat | null = null;
let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient) {
    if (!process.env.API_KEY) return null;
    aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiClient;
};

export const initializeChat = async () => {
    const ai = getClient();
    if (!ai) return null;

    try {
        // Fix: Updated model name to 'gemini-3-flash-preview' for basic text tasks
        chatSession = ai.chats.create({
            model: 'gemini-3-flash-preview',
            config: {
                systemInstruction: `You are the specialized AI assistant for 'BookMarket'. 
                Platform Features:
                1. Book Types & Commissions:
                   - Paper Books (الكتب الورقية): 15% commission.
                   - E-books (الكتب الإلكترونية): 10% commission.
                   - Audiobooks (الكتب الصوتية): 5% commission.
                2. Payments: Supports Crypto (SOL, ETH, BTC, MONAD, BASE, SUI, MATIC) and local currencies.
                3. Listing Limits:
                   - Free users: Max 3 books.
                   - Premium users: Unlimited books.
                4. Gifting: Users can buy books as gifts.
                5. Support Links:
                   - Wordpress: https://jacobalcadiapps.wordpress.com
                   - Blogspot: https://jacobalcadiapps.blogspot.com

                Always answer in the user's language (Arabic/English). 
                Be enthusiastic about reading and tech. 
                If technical help is needed, refer them to jikob67@gmail.com.`,
            },
        });
        return chatSession;
    } catch (error) {
        console.error("Failed to initialize chat", error);
        return null;
    }
};

export const sendMessageToAI = async (message: string): Promise<string> => {
    if (!chatSession) await initializeChat();
    if (!chatSession) return "Service temporarily unavailable.";

    try {
        const response = await chatSession.sendMessage({ message });
        return response.text || "Could you repeat that?";
    } catch (error) {
        return "I'm having trouble connecting. Please try again later.";
    }
};

