                            className="w-full p-5 bg-gray-50 border-2 border-gray-100 rounded-3xl focus:border-accent outline-none font-mono text-sm"
                        />
                    </div>
                )}

                {step === 5 && (
                    <div className="py-12 text-center space-y-4 animate-in zoom-in duration-500">
                        <div className="w-24 h-24 bg-accent rounded-full flex items-center justify-center mx-auto shadow-2xl shadow-accent/40 animate-bounce">
