              </div>
          </div>
      )}

      {/* Enterprise Only Branding Settings */}
      {isOwnProfile && targetUser.subscriptionTier === 'Enterprise' && (
        <div className="bg-white p-8 rounded-[3rem] border-2 border-accent/20 space-y-4">
