import React, { useState } from 'react';
import { MOCK_USER, WALLETS, SUBSCRIPTION_PLANS, MOCK_BOOKS } from '../constants';
import { CheckCircle, Copy, ShieldCheck, ChevronRight, Check, Star, Globe, Zap, Headset, BarChart3, Settings, MessageSquare, ArrowLeft, MoreHorizontal } from 'lucide-react';
import { SubscriptionTier, SubscriptionPeriod, CryptoWallet, PlanDetails, User } from '../types';
import { useNavigate, useParams, Link } from 'react-router-dom';
import { useTranslation } from '../context/LanguageContext';

const Profile: React.FC = () => {
  const { userId } = useParams();
  const navigate = useNavigate();
  const { t, isRtl } = useTranslation();

  const [step, setStep] = useState(1);
  const [selectedPlan, setSelectedPlan] = useState<PlanDetails | null>(null);
  const [selectedPeriod, setSelectedPeriod] = useState<SubscriptionPeriod>('Monthly');
  const [selectedWallet, setSelectedWallet] = useState<CryptoWallet | null>(null);
  const [userAddress, setUserAddress] = useState('');
  const [txHash, setTxHash] = useState('');

  const isOwnProfile = !userId || userId === MOCK_USER.id;

  const targetUser: User = isOwnProfile ? MOCK_USER : {
    id: userId!,
    username: `@user_${userId}`,
    fullName: `Verified Seller ${userId}`,
    avatarUrl: `https://ui-avatars.com/api/?name=User+${userId}&background=random`,
    points: 850,
    isVerified: true,
    role: 'seller',
    subscriptionTier: 'Pro',
    listingCount: 3
  };

  const activePlan = SUBSCRIPTION_PLANS.find(p => p.id === targetUser.subscriptionTier) || { limit: 5, id: 'Newbie' };
  const isPremium = targetUser.subscriptionTier === 'Pro' || targetUser.subscriptionTier === 'Enterprise';

  // Logical Badge Visibility (Basic and above)
  const hasVerificationBadge = targetUser.subscriptionTier !== 'Newbie' && targetUser.subscriptionTier !== 'Free';

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert('Address copied!');
  };

  const isStepComplete = (currentStep: number) => {
    switch(currentStep) {
      case 1: return selectedPlan !== null;
      case 2: return selectedWallet !== null;
      case 3: return userAddress.trim().length > 10;
      case 4: return txHash.trim().length > 5;
      default: return true;
    }
  };

  const resetFlow = () => {
      setStep(1);
      setSelectedPlan(null);
      setSelectedWallet(null);
      setUserAddress('');
      setTxHash('');
  };

  const getFeatureIcon = (feature: string) => {
    if (feature.includes('List')) return <Star className="w-3 h-3" />;
    if (feature.includes('Support')) return <Headset className="w-3 h-3" />;
    if (feature.includes('Badge') || feature.includes('Verified')) return <CheckCircle className="w-3 h-3" />;
    if (feature.includes('Featured') || feature.includes('Analytics')) return <Zap className="w-3 h-3" />;
    return <Globe className="w-3 h-3" />;
  };

  return (
    <div className="px-4 py-8 space-y-8 max-w-2xl mx-auto pb-32">
      {!isOwnProfile && (
          <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-400 hover:text-black font-black text-xs uppercase tracking-widest transition-colors mb-4">
              <ArrowLeft className={`w-4 h-4 ${isRtl ? 'rotate-180' : ''}`} /> Back
          </button>
      )}

      {/* User Info Card */}
      <div className="bg-white rounded-[2.5rem] border border-gray-100 shadow-xl p-8 flex flex-col items-center relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-24 bg-gradient-to-br from-accent/20 to-transparent z-0"></div>
        <div className="relative z-10">
            <img src={targetUser.avatarUrl} alt="Avatar" className="w-24 h-24 rounded-full border-4 border-white shadow-xl" />
            {hasVerificationBadge && (
                <div className="absolute -bottom-2 -right-2 bg-blue-500 p-1.5 rounded-full border-4 border-white shadow-lg animate-bounce">
                    <Check className="w-4 h-4 text-white stroke-[4px]" />
                </div>
            )}
        </div>

        <h2 className="text-2xl font-black text-gray-900 mt-4 flex items-center gap-2">
            {targetUser.fullName}
            {targetUser.subscriptionTier === 'Enterprise' && <ShieldCheck className="w-5 h-5 text-accent" />}
        </h2>
        <div className="flex items-center gap-1 text-accent-hover font-bold text-sm">
            {targetUser.username}
        </div>

        {/* Tier Limits Progress Bar */}
        {isOwnProfile && (
            <div className="w-full mt-6 space-y-2">
                <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-gray-400">
                    <span>{t('listings')}</span>
                    <span>{targetUser.listingCount} / {activePlan.limit === Infinity ? '∞' : activePlan.limit}</span>
                </div>
                <div className="w-full h-2 bg-gray-100 rounded-full overflow-hidden">
                    <div 
                        className="h-full bg-accent transition-all duration-1000"
                        style={{ width: `${activePlan.limit === Infinity ? 100 : (targetUser.listingCount / activePlan.limit) * 100}%` }}
                    />
                </div>
            </div>
        )}

        <div className="mt-6 flex gap-4 w-full">
            <div className="flex-1 bg-gray-50 p-4 rounded-2xl text-center">
                <span className="block text-xl font-black">{targetUser.listingCount}</span>
                <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{t('listings')}</span>
            </div>
            <div className="flex-1 bg-black text-white p-4 rounded-2xl text-center border-b-4 border-accent relative">
                <span className="block text-xl font-black uppercase text-accent">{targetUser.subscriptionTier}</span>
                <span className="text-[10px] opacity-50 font-bold uppercase tracking-widest">{t('plan')}</span>
                {isPremium && <Zap className="absolute top-2 right-2 w-3 h-3 text-accent animate-pulse" />}
            </div>
        </div>

        {!isOwnProfile ? (
            <Link 
                to={`/chat/${targetUser.id}`}
                className="mt-6 w-full py-5 bg-accent text-black rounded-3xl flex items-center justify-center gap-3 font-black text-sm uppercase tracking-widest shadow-xl shadow-accent/20 hover:scale-[1.02] transition-all group"
            >
                <MessageSquare className="w-5 h-5 fill-black" /> {t('message')}
            </Link>
        ) : (
            <div className="w-full space-y-2 mt-6">
                {isPremium && (
                    <button 
                        onClick={() => navigate('/stats')}
                        className="w-full py-4 bg-gray-900 text-white rounded-2xl flex items-center justify-center gap-3 font-black text-xs uppercase tracking-widest hover:bg-accent hover:text-black transition-all group shadow-xl"
                    >
                        <BarChart3 className="w-4 h-4 text-accent" /> {isRtl ? 'تحليلات السوق (برو)' : 'Market Analytics (Pro)'}
                    </button>
                )}
                <button className="w-full py-4 bg-gray-50 text-gray-400 rounded-2xl flex items-center justify-center gap-3 font-black text-xs uppercase tracking-widest hover:bg-gray-100 transition-all">
                    <Settings className="w-4 h-4" /> Account Settings
                </button>
            </div>
        )}
      </div>

      {/* Subscription Wizard (Only for Me) */}
      {isOwnProfile && (
          <div className="bg-white rounded-[2.5rem] border border-gray-100 shadow-2xl overflow-hidden relative">
            <div className="bg-black text-white p-6 flex justify-between items-center">
                <h3 className="font-black text-sm flex items-center gap-2">
                    <ShieldCheck className="w-5 h-5 text-accent" /> UPGRADE HUB
                </h3>
                <span className="text-[10px] font-black bg-accent text-black px-2 py-1 rounded">STEP {step}/5</span>
            </div>

            <div className="p-8">
                {step === 1 && (
                    <div className="space-y-6 animate-in fade-in duration-500">
                        <div className="flex p-1 bg-gray-100 rounded-2xl">
                            {(['Daily', 'Monthly', 'Yearly'] as SubscriptionPeriod[]).map(p => (
                                <button 
                                    key={p}
                                    onClick={() => setSelectedPeriod(p)}
                                    className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedPeriod === p ? 'bg-white shadow-sm text-black' : 'text-gray-400'}`}
                                >
                                    {p}
                                </button>
                            ))}
                        </div>
                        <div className="grid grid-cols-1 gap-4">
                            {SUBSCRIPTION_PLANS.map(plan => (
                                <div 
                                    key={plan.id}
                                    onClick={() => setSelectedPlan(plan)}
                                    className={`p-5 rounded-3xl border-2 transition-all cursor-pointer relative ${selectedPlan?.id === plan.id ? 'border-accent bg-accent/5 ring-4 ring-accent/10' : 'border-gray-50 hover:border-gray-200'}`}
                                >
                                    <div className="flex justify-between items-start mb-3">
                                        <div>
                                            <span className="font-black text-gray-900 text-lg">{plan.name}</span>
                                            <div className="text-accent-hover font-black text-xl mt-1">${plan.prices[selectedPeriod]}</div>
                                        </div>
                                        {selectedPlan?.id === plan.id && <CheckCircle className="w-6 h-6 text-accent fill-black" />}
                                    </div>
                                    <div className="space-y-2">
                                        {plan.features.map((f, i) => (
                                            <div key={i} className="flex items-center gap-2 text-[10px] font-bold text-gray-500">
                                                {getFeatureIcon(f)}
                                                {f}
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {step === 2 && (
                    <div className="space-y-4 animate-in slide-in-from-right-4 duration-500">
                        <p className="text-xs font-black text-gray-400 uppercase tracking-widest mb-6">Select Payment Wallet:</p>
                        <div className="grid grid-cols-1 gap-3">
                            {WALLETS.map(w => (
                                <button 
                                    key={w.symbol}
                                    onClick={() => setSelectedWallet(w)}
                                    className={`flex items-center justify-between p-5 rounded-3xl border-2 transition-all ${selectedWallet?.symbol === w.symbol ? 'border-accent bg-accent/5' : 'border-gray-50'}`}
                                >
                                    <div className="flex items-center gap-4">
                                        <div className="w-10 h-10 bg-black rounded-xl flex items-center justify-center text-xs font-black text-accent uppercase">{w.symbol.slice(0,2)}</div>
                                        <div className="text-left">
                                            <p className="font-black text-gray-900">{w.name}</p>
                                            <p className="text-[10px] text-gray-400 font-mono truncate max-w-[150px]">{w.address}</p>
                                        </div>
                                    </div>
                                    <div onClick={(e) => { e.stopPropagation(); copyToClipboard(w.address); }} className="p-2 bg-gray-100 hover:bg-black hover:text-white rounded-xl transition-all">
                                        <Copy className="w-4 h-4" />
                                    </div>
                                </button>
                            ))}
                        </div>
                    </div>
                )}

                {step === 3 && (
                    <div className="space-y-6 animate-in slide-in-from-right-4">
                        <div className="bg-black text-accent p-6 rounded-[2rem] text-xs font-black uppercase tracking-widest leading-relaxed">
                            Input the address you are paying from for blockchain validation.
                        </div>
                        <input 
                            type="text"
                            value={userAddress}
                            onChange={(e) => setUserAddress(e.target.value)}
                            placeholder="0x... or Solana Address"
                            className="w-full p-5 bg-gray-50 border-2 border-gray-100 rounded-3xl focus:border-accent outline-none font-mono text-sm"
                        />
                    </div>
                )}

                {step === 4 && (
                    <div className="space-y-6 animate-in slide-in-from-right-4">
                        <div className="bg-accent/10 text-black p-6 rounded-[2rem] text-xs font-black uppercase tracking-widest border border-accent/20">
                            Paste your Transaction Hash to confirm payment.
                        </div>
                        <input 
                            type="text"
                            value={txHash}
                            onChange={(e) => setTxHash(e.target.value)}
                            placeholder="TX-HASH-..."
                            className="w-full p-5 bg-gray-50 border-2 border-gray-100 rounded-3xl focus:border-accent outline-none font-mono text-sm"
                        />
                    </div>
                )}

                {step === 5 && (
                    <div className="py-12 text-center space-y-4 animate-in zoom-in duration-500">
                        <div className="w-24 h-24 bg-accent rounded-full flex items-center justify-center mx-auto shadow-2xl shadow-accent/40 animate-bounce">
                            <Check className="w-12 h-12 text-black stroke-[4px]" />
                        </div>
                        <h4 className="text-3xl font-black text-gray-900 uppercase tracking-tighter">SUCCESSFUL!</h4>
                        <p className="text-gray-500 text-xs font-bold max-w-xs mx-auto leading-relaxed uppercase">
                            Account upgrade in progress. Verified features will be live within minutes.
                        </p>
                        <button onClick={resetFlow} className="mt-8 text-black bg-accent px-8 py-3 rounded-full font-black text-xs uppercase tracking-widest shadow-lg shadow-accent/20 hover:scale-110 transition-all">
                            DONE
                        </button>
                    </div>
                )}

                {step < 5 && (
                    <div className="mt-10 flex gap-4">
                        {step > 1 && (
                            <button 
                                onClick={() => setStep(step - 1)}
                                className="flex-1 py-5 rounded-3xl font-black text-xs uppercase tracking-widest text-gray-400 border-2 border-gray-50 hover:bg-gray-50 transition-all"
                            >
                                {t('previous')}
                            </button>
                        )}
                        <button 
                            disabled={!isStepComplete(step)}
                            onClick={() => setStep(step + 1)}
                            className={`flex-[2] py-5 rounded-3xl font-black text-xs uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${isStepComplete(step) ? 'bg-black text-white shadow-2xl shadow-black/20' : 'bg-gray-100 text-gray-300 cursor-not-allowed'}`}
                        >
                            {step === 4 ? t('confirm') : t('next')} <ChevronRight className="w-4 h-4" />
                        </button>
                    </div>
                )}
            </div>
          </div>
      )}

      {/* Enterprise Only Branding Settings */}
      {isOwnProfile && targetUser.subscriptionTier === 'Enterprise' && (
        <div className="bg-white p-8 rounded-[3rem] border-2 border-accent shadow-2xl space-y-4 animate-in slide-in-from-bottom-4">
            <h4 className="font-black text-xs uppercase tracking-widest flex items-center gap-2">
                <ShieldCheck className="w-4 h-4 text-accent" /> Elite Business Control
            </h4>
            <div className="grid grid-cols-1 gap-3">
                <button className="p-5 bg-gray-50 hover:bg-accent rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all flex justify-between items-center">
                    Custom Profile Theme Color <MoreHorizontal className="w-4 h-4" />
                </button>
                <button className="p-5 bg-gray-50 hover:bg-accent rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all flex justify-between items-center">
                    Upload Enterprise Logo <MoreHorizontal className="w-4 h-4" />
                </button>
                <div className="p-4 bg-accent/10 rounded-2xl text-[8px] font-bold text-gray-500 uppercase tracking-widest">
                    Note: Your branding will be visible to all users visiting your profile.
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

