                            <p className="opacity-60 mt-1">{isRtl ? 'العمولة: 0% - الأرباح كاملة لك' : 'COMMISSION: 0% - KEEP ALL PROFIT'}</p>
                        </div>
                    </div>
                )}

                {isPro && (
