                        />
                        <span className="absolute left-8 top-1/2 -translate-y-1/2 text-gray-300 font-black text-xs uppercase tracking-widest">{currency}</span>
                    </div>
                    <select 
                        value={currency}
                        onChange={(e) => setCurrency(e.target.value)}
                        className="flex-1 p-6 bg-gray-100 rounded-[2rem] border-none focus:ring-4 focus:ring-accent font-black text-xs uppercase"
                    >
                        <option>USD</option>
                        <option>SOL</option>
                        <option>ETH</option>
                        <option>BTC</option>
                    </select>
                </div>

                <div className="bg-black text-white p-10 rounded-[3.5rem] space-y-6 relative overflow-hidden shadow-2xl border-t-8 border-accent">
                    <div className="flex justify-between items-center text-[10px] font-black tracking-widest uppercase opacity-40">
                        <span>Platform Tax ({activeCommission*100}%)</span>
                        <span className={activeCommission === 0 ? 'text-accent' : ''}>
                            {activeCommission === 0 ? 'EXEMPT' : `-${(price * activeCommission).toFixed(2)} ${currency}`}
                        </span>
                    </div>
                    <div className="flex justify-between items-center pt-8 border-t border-white/10">
                        <span className="font-black text-sm uppercase tracking-widest">Your Net Profit</span>
                        <span className="text-5xl font-black text-accent tracking-tighter">
