const AddListing = () => {
    const { t, isRtl } = useTranslation();
    const navigate = useNavigate();

    // Form State
    const [title, setTitle] = useState('');
    const [type, setType] = useState<BookType>('Paper');
    const [price, setPrice] = useState<number>(0);
    const [currency, setCurrency] = useState('USD');
    const [isPublishing, setIsPublishing] = useState(false);

    // Business Logic Checks
    // Fix: Using SUBSCRIPTION_PLANS[0] as fallback ensures activePlan always matches the PlanDetails interface (including 'name' property).
    const activePlan = SUBSCRIPTION_PLANS.find(p => p.id === MOCK_USER.subscriptionTier) || SUBSCRIPTION_PLANS[0];
    const currentCount = Number(localStorage.getItem('book_user_listings_count') || '0');
    const reachedLimit = currentCount >= activePlan.limit;
    const isPro = MOCK_USER.subscriptionTier === 'Pro';
    const isEnterprise = MOCK_USER.subscriptionTier === 'Enterprise';
    const activeCommission = isEnterprise ? 0 : COMMISSIONS[type];

    const handlePublish = (e: React.FormEvent) => {
        e.preventDefault();
        if (!title || price <= 0 || reachedLimit) return;

        setIsPublishing(true);

        const newBook: Book = {
            id: Math.random().toString(36).substr(2, 9),
            title,
            author: MOCK_USER.fullName,
            price,
            currency,
            coverUrl: '', // In real app, handle upload
            sellerId: MOCK_USER.id,
            type,
            category: isPro ? 'Featured' : 'General',
            description: '',
            commissionRate: activeCommission
        };

        const existing = JSON.parse(localStorage.getItem('book_listings') || '[]');
        localStorage.setItem('book_listings', JSON.stringify([newBook, ...existing]));
        localStorage.setItem('book_user_listings_count', (currentCount + 1).toString());

        setTimeout(() => {
            setIsPublishing(false);
            navigate('/');
        }, 1500);
    };

    return (
        <div className="p-6 max-w-2xl mx-auto space-y-8 pb-32 animate-in slide-in-from-bottom-6 duration-500">
            <div className="flex justify-between items-start">
                <div className={isRtl ? 'text-right' : 'text-left'}>
                    <h2 className="text-5xl font-black text-gray-900 uppercase tracking-tighter italic">
                      {isRtl ? 'نشر إعلان' : 'List Assets'}
                    </h2>
                    <p className="text-gray-400 font-bold text-[10px] uppercase tracking-widest mt-2">
                      {isRtl ? 'قم بتحويل كتبك إلى أرباح فورية' : 'Monetize your physical or digital library'}
                    </p>
                </div>
                <div className="bg-black p-5 rounded-[2.5rem] text-center min-w-[120px] border-b-8 border-accent shadow-2xl">
                    <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1">{t('plan')}</p>
                    <p className={`text-xl font-black ${reachedLimit ? 'text-red-500 animate-pulse' : 'text-accent'}`}>
                      {currentCount} / {activePlan.limit === Infinity ? '∞' : activePlan.limit}
                    </p>
                </div>
            </div>

            <div className="space-y-3">
                {isEnterprise && (
                    <div className="bg-black text-accent p-6 rounded-[2.5rem] flex items-center gap-4 font-black text-[10px] uppercase tracking-widest border-2 border-accent shadow-2xl">
                        <div className="p-3 bg-accent/20 rounded-2xl"><ShieldCheck className="w-6 h-6" /></div>
                        <div>
                            <p>{isRtl ? 'ميزة التاجر الذهبي مفعلة' : 'Business Elite Status: Active'}</p>
                            <p className="opacity-60 mt-1">{isRtl ? 'العمولة: 0% - الأرباح كاملة لك' : 'COMMISSION: 0% - KEEP ALL PROFIT'}</p>
                        </div>
                    </div>
                )}

                {isPro && (
                    <div className="bg-accent text-black p-6 rounded-[2.5rem] flex items-center gap-4 font-black text-[10px] uppercase tracking-widest shadow-2xl">
                        <div className="p-3 bg-black/10 rounded-2xl"><Zap className="w-6 h-6 fill-black" /></div>
                        <div>
                            <p>{isRtl ? 'تثبيت الإعلانات مفعل' : 'Auto-Featured Active'}</p>
                            <p className="opacity-60 mt-1">{isRtl ? 'سيظهر إعلانك في واجهة التطبيق فوراً' : 'YOUR BOOK WILL BE FRONT-PAGE FEATURED'}</p>
                        </div>
                    </div>
                )}
            </div>

            {reachedLimit && (
                <div className="bg-red-50 border-4 border-red-100 p-10 rounded-[3rem] flex flex-col items-center text-center gap-6 animate-in zoom-in shadow-xl">
                    <div className="w-20 h-20 bg-red-100 rounded-full flex items-center justify-center border-4 border-white shadow-lg">
                        <AlertTriangle className="w-10 h-10 text-red-500" />
                    </div>
                    <div>
                        <h4 className="font-black text-red-900 text-2xl uppercase tracking-tighter">Inventory Limit!</h4>
                        <p className="text-[11px] font-bold text-red-700 mt-2 mb-8 uppercase tracking-widest leading-relaxed">You've hit the max listings for {activePlan.name}.<br/>Upgrade now for massive scale.</p>
                        <button onClick={() => navigate('/profile')} className="w-full py-5 bg-red-500 text-white rounded-[2rem] text-xs font-black uppercase tracking-widest shadow-2xl shadow-red-500/30 active:scale-95 transition-all">Go Unlimited</button>
                    </div>
                </div>
            )}

            <form onSubmit={handlePublish} className={`space-y-8 ${reachedLimit ? 'opacity-20 grayscale pointer-events-none' : ''}`}>
                <div className="grid grid-cols-3 gap-4">
                    {(['Paper', 'E-book', 'Audiobook'] as BookType[]).map(t_type => (
                        <button 
                            key={t_type}
                            type="button"
                            onClick={() => setType(t_type)}
                            className={`py-8 rounded-[2.5rem] border-4 font-black text-[10px] uppercase tracking-widest transition-all ${type === t_type ? 'border-accent bg-black text-white shadow-2xl scale-105' : 'border-gray-50 text-gray-400 hover:border-accent/30'}`}
                        >
                            {t_type}
                        </button>
                    ))}
                </div>

                <div className="group relative">
                    <input 
                        type="text" 
                        required
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        placeholder={isRtl ? "عنوان الكتاب أو الأصل الرقمي..." : "Book Title or Asset Name..."} 
                        className="w-full p-8 bg-gray-50 rounded-[2.5rem] border-4 border-transparent focus:border-accent outline-none font-black text-xl tracking-tighter shadow-inner transition-all" 
                    />
                </div>

                <div className="flex gap-4">
                    <div className="flex-[3] relative">
                        <input 
                            type="number" 
                            required
                            min="1"
                            value={price}
                            onChange={(e) => setPrice(Number(e.target.value))}
                            className="w-full p-8 bg-gray-50 rounded-[2.5rem] border-4 border-transparent focus:border-accent outline-none font-black text-4xl text-left shadow-inner" 
                        />
                        <span className="absolute left-8 top-1/2 -translate-y-1/2 text-gray-300 font-black text-xs uppercase tracking-widest">{currency}</span>
                    </div>
                    <select 
                        value={currency}
                        onChange={(e) => setCurrency(e.target.value)}
                        className="flex-1 p-6 bg-gray-100 rounded-[2rem] border-none focus:ring-4 focus:ring-accent font-black text-xs uppercase"
                    >
                        <option>USD</option>
                        <option>SOL</option>
                        <option>ETH</option>
                        <option>BTC</option>
                    </select>
                </div>

                <div className="bg-black text-white p-10 rounded-[3.5rem] space-y-6 relative overflow-hidden shadow-2xl border-t-8 border-accent">
                    <div className="flex justify-between items-center text-[10px] font-black tracking-widest uppercase opacity-40">
                        <span>Platform Tax ({activeCommission*100}%)</span>
                        <span className={activeCommission === 0 ? 'text-accent' : ''}>
                            {activeCommission === 0 ? 'EXEMPT' : `-${(price * activeCommission).toFixed(2)} ${currency}`}
                        </span>
                    </div>
                    <div className="flex justify-between items-center pt-8 border-t border-white/10">
                        <span className="font-black text-sm uppercase tracking-widest">Your Net Profit</span>
                        <span className="text-5xl font-black text-accent tracking-tighter">
                            {(price - (price * activeCommission)).toFixed(2)}
                        </span>
                    </div>
                    <ShieldCheck className="absolute -left-10 -bottom-10 w-48 h-48 text-white/5 rotate-12" />
                </div>

                <button 
                    disabled={isPublishing}
                    className="w-full bg-accent text-black py-8 rounded-[3rem] font-black text-xl uppercase tracking-widest shadow-2xl shadow-accent/40 hover:bg-white border-4 border-accent transition-all flex items-center justify-center gap-4"
                >
                    {isPublishing ? (
                        <div className="w-8 h-8 border-4 border-black border-t-transparent rounded-full animate-spin"></div>
                    ) : (
                        <> {isRtl ? 'تأكيد ونشر' : 'Confirm & Publish'} <Check className="w-6 h-6 stroke-[4px]" /> </>
                    )}
                </button>
            </form>
        </div>
    );
};

