    ...MOCK_USER, 
    listingCount: localListings.length 
  } : {
    id: userId!,
    username: `@user_${userId}`,
    fullName: `User ${userId}`,
    avatarUrl: `https://ui-avatars.com/api/?name=${userId}&background=random`,
