                        />
                    </div>
                )}

                {step === 4 && (
                    <div className="space-y-8 animate-in slide-in-from-right-10">
                        <div className="bg-accent/10 text-black p-8 rounded-[2.5rem] text-[10px] font-black uppercase tracking-widest border-4 border-accent/20 shadow-xl">
