import React, { useState, useRef, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
    Send, Paperclip, MapPin, Mic, Video, Phone, Image as ImageIcon, 
    FileText, Play, X, ChevronLeft, MoreVertical, Smartphone, Info, MessageSquare
} from 'lucide-react';
import { useTranslation } from '../context/LanguageContext';
import { ChatMessage, MessageType, User, Book } from '../types';
import { MOCK_USER } from '../constants';

const Chat: React.FC = () => {
    const { t, isRtl } = useTranslation();
    const { userId } = useParams();
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [inputValue, setInputValue] = useState('');
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [peerUser, setPeerUser] = useState<User | null>(null);

    const scrollRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        // Resolve Peer User from real listings data
        const savedListings: Book[] = JSON.parse(localStorage.getItem('book_listings') || '[]');
        const sellerMatch = savedListings.find(b => b.sellerId === userId);

        if (sellerMatch) {
            setPeerUser({
                id: userId!,
                username: `@${sellerMatch.author.toLowerCase().replace(/\s+/g, '')}`,
                fullName: sellerMatch.author,
                avatarUrl: `https://ui-avatars.com/api/?name=${sellerMatch.author}&background=00FFBA&color=000`,
                points: 0,
                isVerified: true,
                role: 'seller',
                subscriptionTier: 'Basic',
                listingCount: 0
            });
        } else {
            // Default real-time generated identity if not found in listings
            setPeerUser({
                id: userId || 'anon',
                username: `@user_${userId || '0'}`,
                fullName: userId ? `${isRtl ? 'مستخدم' : 'User'} ${userId}` : (isRtl ? 'مستخدم مجهول' : 'Anonymous User'),
                avatarUrl: `https://ui-avatars.com/api/?name=${userId || 'U'}&background=random`,
                points: 0,
                isVerified: false,
                role: 'buyer',
                subscriptionTier: 'Newbie',
                listingCount: 0
            });
        }
    }, [userId, isRtl]);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
        }
    }, [messages]);

    const handleSend = (type: MessageType = 'text', content: string = inputValue) => {
        if (!content.trim() && type === 'text') return;

        const newMsg: ChatMessage = {
            id: Date.now().toString(),
            senderId: MOCK_USER.id,
            type,
            content,
            timestamp: new Date()
        };

        setMessages(prev => [...prev, newMsg]);
        if (type === 'text') setInputValue('');
    };

    const shareLocation = () => {
        if (navigator.geolocation) {
            navigator.geolocation.getCurrentPosition((pos) => {
                const coords = `${pos.coords.latitude},${pos.coords.longitude}`;
                handleSend('location', coords);
            });
        }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const type: MessageType = file.type.startsWith('image') ? 'image' : 
                            file.type.startsWith('video') ? 'video' : 
                            file.type.startsWith('audio') ? 'audio' : 'file';

        handleSend(type, URL.createObjectURL(file));
    };

    if (!peerUser) return null;

    return (
        <div className="fixed inset-0 z-50 bg-white flex flex-col md:relative md:h-[calc(100vh-140px)] md:inset-auto">
            {/* Header */}
            <header className="bg-black text-white p-4 flex items-center justify-between border-b border-white/10">
                <div className="flex items-center gap-3">
                    <Link to={-1 as any} className="md:hidden">
                        <ChevronLeft className={`w-6 h-6 ${isRtl ? 'rotate-180' : ''}`} />
                    </Link>
                    <Link to={`/user/${peerUser.id}`} className="flex items-center gap-3">
                        <div className="relative">
                            <img src={peerUser.avatarUrl} className="w-10 h-10 rounded-full border-2 border-accent" />
                        </div>
                        <div className={isRtl ? 'text-right' : 'text-left'}>
                            <p className="font-black text-sm tracking-tighter">{peerUser.fullName}</p>
                            <p className="text-[8px] text-gray-500 uppercase font-black tracking-widest">{peerUser.username}</p>
                        </div>
                    </Link>
                </div>
                <div className="flex items-center gap-4">
                    <button className="p-2 hover:bg-white/10 rounded-full transition-colors"><Phone className="w-5 h-5 text-gray-400" /></button>
                    <button className="p-2 hover:bg-white/10 rounded-full transition-colors"><Video className="w-5 h-5 text-gray-400" /></button>
                    <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><MoreVertical className="w-5 h-5" /></button>
                </div>
            </header>

            {/* Messages Area */}
            <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 bg-gray-50 custom-scrollbar">
                {messages.length === 0 && (
                    <div className="h-full flex flex-col items-center justify-center opacity-20 text-center space-y-4 animate-in fade-in duration-500">
                        <div className="w-20 h-20 bg-gray-200 rounded-full flex items-center justify-center mb-2">
                             <MessageSquare className="w-10 h-10 text-black" />
                        </div>
                        <p className="font-black uppercase tracking-widest text-xs">{t('noChats')}</p>
                        <p className="text-[10px] font-bold max-w-xs">{isRtl ? 'ابدأ المحادثة الآن بطريقة آمنة ومشفرة' : 'Start a safe and encrypted conversation now'}</p>
                    </div>
                )}
                {messages.map((msg) => {
                    const isMe = msg.senderId === MOCK_USER.id;
                    return (
                        <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
                            <div className={`max-w-[75%] space-y-1 ${isMe ? 'text-right' : 'text-left'}`}>
                                <div className={`p-4 rounded-[1.5rem] shadow-sm text-sm font-medium ${
                                    isMe ? 'bg-black text-white rounded-br-none' : 'bg-white text-gray-900 rounded-bl-none border border-gray-100'
                                }`}>
                                    {msg.type === 'text' && msg.content}
                                    {msg.type === 'image' && <img src={msg.content} className="rounded-xl max-h-60 w-full object-cover" />}
                                    {msg.type === 'video' && <video src={msg.content} controls className="rounded-xl max-h-60" />}
                                    {msg.type === 'audio' && <audio src={msg.content} controls className="w-full h-8" />}
                                    {msg.type === 'file' && (
                                        <div className="flex items-center gap-3">
                                            <FileText className="w-8 h-8 opacity-50" />
                                            <span className="truncate max-w-[150px]">{msg.fileName || 'Attachment'}</span>
                                        </div>
                                    )}
                                    {msg.type === 'location' && (
                                        <a href={`https://www.google.com/maps?q=${msg.content}`} target="_blank" className="flex flex-col gap-2">
                                            <div className="flex items-center gap-2 text-accent">
                                                <MapPin className="w-4 h-4" /> <span>{t('sendLocation')}</span>
                                            </div>
                                            <div className="bg-gray-100 p-4 rounded-xl text-center text-[10px] font-bold uppercase">View on Map</div>
                                        </a>
                                    )}
                                </div>
                                <p className="text-[8px] text-gray-400 font-bold uppercase">{msg.timestamp.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* Input Bar */}
            <div className="p-4 bg-white border-t border-gray-100 pb-safe">
                <div className="flex items-end gap-3 max-w-7xl mx-auto">
                    <div className="flex gap-1 mb-1">
