    const videoRef = useRef<HTMLVideoElement>(null);
    const streamRef = useRef<MediaStream | null>(null);

    useEffect(() => {
        if (userId === 'support' || !userId) {
            setIsAI(true);
            setPeerUser({
                id: 'support',
                username: '@support',
                fullName: isRtl ? 'دعم book الذكي' : 'book Support AI',
