let chatSession: Chat | null = null;
let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient) {
    if (!process.env.API_KEY) return null;
    aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiClient;
};

export const initializeChat = async () => {
    const ai = getClient();
    if (!ai) return null;

    try {
        chatSession = ai.chats.create({
            model: 'gemini-3-flash-preview',
            config: {
                systemInstruction: `You are the specialized AI assistant for 'book'. 
                User Info: Name: ${MOCK_USER.fullName}, Tier: ${MOCK_USER.subscriptionTier}.

                Tier-Specific Handling:
                - Enterprise: Offer dedicated human-support escalation if needed. Emphasize their 0% commission advantage.
                - Pro: Discuss advanced market analytics and social promo strategies.
                - Basic/Newbie: Encourage upgrading for better visibility and lower limits.

                Platform Features:
                1. Book Types: Paper (15% comm), E-book (10% comm), Audio (5% comm).
                2. Enterprise Perk: 0% Platform Commission.
                3. Market DNA: Pro users get a special stats page.

                Always answer in the user's language. Refer technical queries to jikob67@gmail.com.`,
            },
        });
        return chatSession;
    } catch (error) {
        console.error("Failed to initialize chat", error);
        return null;
    }
};

export const sendMessageToAI = async (message: string): Promise<string> => {
    if (!chatSession) await initializeChat();
    if (!chatSession) return "Service temporarily unavailable.";

    try {
        const response = await chatSession.sendMessage({ message });
        return response.text || "Could you repeat that?";
    } catch (error) {
        return "I'm having trouble connecting. Please try again later.";
    }
};

/**
 * book Guard AI: فحص المحتوى قبل النشر
 */
export const moderateListingContent = async (listingData: { title: string, type: string }): Promise<{ isAllowed: boolean; reason: string }> => {
    const ai = getClient();
    if (!ai) return { isAllowed: true, reason: "" }; // Fallback if API key missing

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Act as a strict community safety moderator for the 'book' app. 
            Analyze this listing:
            Title: "${listingData.title}"
            Type: "${listingData.type}"

            Strict Rule: Prohibit any content that is unethical, harmful to society, sexually explicit, promotes violence, illegal acts, or violates human dignity.

            Respond ONLY with a JSON object in this format:
            {
                "isAllowed": boolean,
                "reason": "string in Arabic explaining why if not allowed, or empty if allowed"
            }`,
            config: {
                responseMimeType: "application/json",
            }
        });

        const result = JSON.parse(response.text || '{"isAllowed": true, "reason": ""}');
        return result;
    } catch (error) {
        console.error("Moderation error:", error);
        return { isAllowed: true, reason: "" }; // Default to allow if service fails to not block users unfairly, but log it
    }
};

