const AddListing = () => {
    const { t, isRtl } = useTranslation();
    const navigate = useNavigate();

    // Wizard State
    const [step, setStep] = useState(1);
    const [isPublishing, setIsPublishing] = useState(false);
    const [isScanning, setIsScanning] = useState(false);
    const [rejectionReason, setRejectionReason] = useState<string | null>(null);
    const [agreedToEthicalTerms, setAgreedToEthicalTerms] = useState(false);

    // Form Data
    const [title, setTitle] = useState('');
    const [type, setType] = useState<BookType>('Paper');
    const [price, setPrice] = useState<number>(0);
    const [currency, setCurrency] = useState('USD');
    const [payoutNetwork, setPayoutNetwork] = useState<string>(WALLETS[0].name);
    const [images, setImages] = useState<string[]>([]);
    const [digitalFile, setDigitalFile] = useState<File | null>(null);

    const imageInputRef = useRef<HTMLInputElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Business Logic
    const activePlan = SUBSCRIPTION_PLANS.find(p => p.id === MOCK_USER.subscriptionTier) || SUBSCRIPTION_PLANS[0];
    const currentCount = Number(localStorage.getItem('book_user_listings_count') || '0');
    const reachedLimit = currentCount >= activePlan.limit;
    const activeCommission = MOCK_USER.subscriptionTier === 'Enterprise' ? 0 : COMMISSIONS[type];

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files) return;

        const newImages = Array.from(files).map((file: File) => URL.createObjectURL(file));
        setImages(prev => [...prev, ...newImages]);
    };

    const handlePublish = async () => {
        if (!agreedToEthicalTerms) {
            alert(isRtl ? "يجب الموافقة على المعايير الأخلاقية أولاً" : "You must agree to ethical standards first");
            return;
        }

        setIsScanning(true);
        setRejectionReason(null);

        // 1. AI Security Scan (Guard)
        const moderation = await moderateListingContent({ title, type });

        if (!moderation.isAllowed) {
            // Enforcement Protocol
            const strikes = Number(localStorage.getItem('book_user_strikes') || '0') + 1;
            localStorage.setItem('book_user_strikes', strikes.toString());

            // Permanent Ban Logic:
            // High severity violation (Porn, Hate speech) = Instant Ban
            // Strike limit (3) = Instant Ban
            if (moderation.severity === 'high' || strikes >= 3) {
                localStorage.setItem('book_user_banned', 'true');
                window.location.reload(); // Force trigger BannedScreen
                return;
            }

            setRejectionReason(moderation.reason || t('rejected'));
            setIsScanning(false);
            return;
        }

        setIsScanning(false);
        setIsPublishing(true);

        const newBook: Book = {
            id: Math.random().toString(36).substr(2, 9),
            title,
            author: MOCK_USER.fullName,
            price,
            currency,
            coverUrl: images[0] || '',
            sellerId: MOCK_USER.id,
            type,
            category: MOCK_USER.subscriptionTier === 'Pro' ? 'Featured' : 'General',
            description: `Payout via ${payoutNetwork} Network`,
            commissionRate: activeCommission
        };

        const existing = JSON.parse(localStorage.getItem('book_listings') || '[]');
        localStorage.setItem('book_listings', JSON.stringify([newBook, ...existing]));
        localStorage.setItem('book_user_listings_count', (currentCount + 1).toString());

        // Reset strikes upon successful safe publication
        localStorage.setItem('book_user_strikes', '0');

        setTimeout(() => {
            setIsPublishing(false);
            navigate('/');
        }, 1500);
    };

    const isStepValid = () => {
        if (step === 1) return title.trim() !== '' && price > 0 && payoutNetwork !== '';
        if (step === 2) return images.length > 0;
        if (step === 3) {
            if (type === 'Paper') return true;
            return digitalFile !== null;
        }
        if (step === 4) return agreedToEthicalTerms;
        return true;
    };

