    const [price, setPrice] = useState<number>(0);
    const [currency, setCurrency] = useState('USD');
    const [payoutNetwork, setPayoutNetwork] = useState<string>(WALLETS[0].name);
    const [images, setImages] = useState<string[]>([]);
    const [digitalFile, setDigitalFile] = useState<File | null>(null);

    const imageInputRef = useRef<HTMLInputElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Business Logic
    const activePlan = SUBSCRIPTION_PLANS.find(p => p.id === MOCK_USER.subscriptionTier) || SUBSCRIPTION_PLANS[0];
    const currentCount = Number(localStorage.getItem('book_user_listings_count') || '0');
    const reachedLimit = currentCount >= activePlan.limit;
    const activeCommission = MOCK_USER.subscriptionTier === 'Enterprise' ? 0 : COMMISSIONS[type];

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files) return;

        const newImages = Array.from(files).map((file: File) => URL.createObjectURL(file));
        setImages(prev => [...prev, ...newImages]);
    };

    const handleAutoCorrect = async () => {
        if (!rejectionReason) return;
        setIsCorrecting(true);
        try {
            const correction = await suggestCorrectedListing({ title, reason: rejectionReason });
            setTitle(correction.suggestedTitle);
            setRejectionReason(null); // Clear rejection and allow retry
        } catch (error) {
            alert(isRtl ? "فشل نظام التعديل التلقائي" : "Auto-correction system failed");
        } finally {
            setIsCorrecting(false);
        }
    };

    const handlePublish = async () => {
        if (!agreedToEthicalTerms) {
            alert(isRtl ? "يجب الموافقة على المعايير الأخلاقية أولاً" : "You must agree to ethical standards first");
            return;
        }

        setIsScanning(true);
        setRejectionReason(null);

        // 1. AI Security Scan (Guard)
        const moderation = await moderateListingContent({ title, type });

        if (!moderation.isAllowed) {
            // Enforcement Protocol
            const strikes = Number(localStorage.getItem('book_user_strikes') || '0') + 1;
            localStorage.setItem('book_user_strikes', strikes.toString());

            // Permanent Ban Logic:
            if (moderation.severity === 'high' || strikes >= 3) {
                localStorage.setItem('book_user_banned', 'true');
                localStorage.setItem('book_ban_reason', moderation.reason || 'Multiple ethical violations detected');
                window.location.reload(); 
                return;
            }

            setRejectionReason(moderation.reason || t('rejected'));
            setIsScanning(false);
            return;
        }

        setIsScanning(false);
        setIsPublishing(true);

        const newBook: Book = {
            id: Math.random().toString(36).substr(2, 9),
            title,
            author: MOCK_USER.fullName,
            price,
            currency,
            coverUrl: images[0] || '',
            sellerId: MOCK_USER.id,
            type,
            category: MOCK_USER.subscriptionTier === 'Pro' ? 'Featured' : 'General',
            description: `Payout via ${payoutNetwork} Network`,
            commissionRate: activeCommission
        };

        const existing = JSON.parse(localStorage.getItem('book_listings') || '[]');
        localStorage.setItem('book_listings', JSON.stringify([newBook, ...existing]));
        localStorage.setItem('book_user_listings_count', (currentCount + 1).toString());

        localStorage.setItem('book_user_strikes', '0');

        setTimeout(() => {
            setIsPublishing(false);
            navigate('/');
        }, 1500);
    };

    const isStepValid = () => {
        if (step === 1) return title.trim() !== '' && price > 0 && payoutNetwork !== '';
        if (step === 2) return images.length > 0;
        if (step === 3) {
            if (type === 'Paper') return true;
            return digitalFile !== null;
        }
        if (step === 4) return agreedToEthicalTerms;
        return true;
    };

    const stepsLabels = [t('stepInfo'), t('stepMedia'), t('stepFiles'), t('stepReview')];

    return (
        <div className="p-6 max-w-2xl mx-auto space-y-10 pb-40 animate-in slide-in-from-bottom-8 duration-500">
            {/* AI Security Overlay */}
            {(isScanning || isPublishing || isCorrecting || rejectionReason) && (
                <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-8 animate-in fade-in">
                    <div className="w-full max-w-md text-center space-y-8">
                        {rejectionReason ? (
                            <div className="space-y-6 animate-in zoom-in">
                                <div className="w-24 h-24 bg-red-500/20 rounded-[3rem] flex items-center justify-center mx-auto border-4 border-red-500 shadow-[0_0_30px_rgba(239,68,68,0.3)]">
                                    <ShieldAlert className="w-12 h-12 text-red-500" />
                                </div>
                                <div className="space-y-2">
                                    <h3 className="text-3xl font-black text-white italic uppercase tracking-tighter">{t('rejected')}</h3>
                                    <p className="text-red-400 font-bold text-xs uppercase tracking-widest">{isRtl ? 'خرق في البروتوكول الأخلاقي' : 'Ethical Protocol Breach'}</p>
                                </div>

                                <div className="bg-red-950/50 p-6 rounded-[2.5rem] border border-red-900/50 space-y-3">
                                    <p className="text-[10px] font-black text-red-500 uppercase tracking-[0.2em]">{isRtl ? 'سبب الرفض الصريح' : 'SPECIFIC REJECTION REASON'}</p>
                                    <p className="text-white text-sm font-bold leading-relaxed">
                                        {rejectionReason}
                                    </p>
                                </div>

                                <div className="grid grid-cols-1 gap-4 pt-4">
                                    <button 
                                        onClick={handleAutoCorrect}
                                        className="w-full py-5 bg-accent text-black rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl flex items-center justify-center gap-3 hover:scale-105 transition-all"
                                    >
                                        <Wand2 className="w-5 h-5" /> {isRtl ? 'تعديل تلقائي عبر AI (اختياري)' : 'AUTO-FIX WITH AI (OPTIONAL)'}
                                    </button>
                                    <button 
                                        onClick={() => setRejectionReason(null)}
                                        className="w-full py-5 bg-white/5 text-white border border-white/10 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:bg-white/10 transition-all"
                                    >
                                        {isRtl ? 'سأقوم بالتعديل يدوياً' : 'I WILL FIX MANUALLY'}
                                    </button>
                                </div>

                                <p className="text-[9px] font-black text-gray-500 uppercase tracking-widest">{isRtl ? 'تحذير: المخالفات الجسيمة تؤدي للحظر الفوري' : 'WARNING: HIGH SEVERITY LEADS TO INSTANT BAN'}</p>
                            </div>
                        ) : (
                            <div className="space-y-6">
                                <div className="relative w-32 h-32 mx-auto">
                                    <div className="absolute inset-0 bg-accent rounded-[3rem] animate-ping opacity-20"></div>
                                    <div className="relative w-full h-full bg-black border-4 border-accent rounded-[3rem] flex items-center justify-center shadow-[0_0_40px_rgba(0,255,186,0.3)] overflow-hidden">
                                        <div className="absolute inset-0 bg-gradient-to-t from-accent/20 to-transparent animate-pulse"></div>
                                        {isCorrecting ? <Wand2 className="w-16 h-16 text-accent animate-spin" /> : <ShieldCheck className="w-16 h-16 text-accent relative z-10" />}
                                    </div>
                                </div>
                                <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">
                                    {isCorrecting ? (isRtl ? 'جاري تصحيح الإعلان...' : 'Correcting Listing...') : isScanning ? t('scanning') : (isRtl ? 'جاري النشر الآمن...' : 'Safe Publishing...')}
                                </h3>
                                <div className="w-full h-2 bg-white/10 rounded-full overflow-hidden max-w-[200px] mx-auto">
                                    <div className="h-full bg-accent animate-[shimmer_2s_infinite] w-full origin-left"></div>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Header */}
            <div className="flex justify-between items-start">
                <div className={isRtl ? 'text-right' : 'text-left'}>
                    <h2 className="text-4xl font-black text-gray-900 uppercase tracking-tighter italic leading-none">
                      {isRtl ? 'إدراج أصل' : 'List Asset'}
                    </h2>
                    <p className="text-gray-400 font-bold text-[10px] uppercase tracking-widest mt-2">
                        {reachedLimit ? 'Limit reached' : `Step ${step} of 4`}
                    </p>
                </div>
                <div className="bg-black p-5 rounded-[2rem] text-center min-w-[110px] border-b-4 border-accent shadow-2xl">
                    <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1">{t('plan')}</p>
                    <p className={`text-lg font-black ${reachedLimit ? 'text-red-500' : 'text-accent'}`}>
                      {currentCount} / {activePlan.limit === Infinity ? '∞' : activePlan.limit}
                    </p>
                </div>
            </div>

            {/* Visual Stepper */}
            <div className="flex items-center justify-between px-2">
                {stepsLabels.map((label, i) => (
                    <div key={i} className="flex flex-col items-center gap-2">
                        <div className={`w-8 h-8 rounded-full flex items-center justify-center font-black text-xs transition-all ${
                            step > i + 1 ? 'bg-accent text-black' : step === i + 1 ? 'bg-black text-accent ring-4 ring-accent/20' : 'bg-gray-100 text-gray-400'
                        }`}>
                            {step > i + 1 ? <Check className="w-4 h-4 stroke-[4px]" /> : i + 1}
                        </div>
                        <span className={`text-[8px] font-black uppercase tracking-widest ${step === i + 1 ? 'text-black' : 'text-gray-300'}`}>{label}</span>
                    </div>
                ))}
            </div>

            {!reachedLimit && (
                <div className="space-y-8 min-h-[400px]">
                    {step === 1 && (
                        <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
                            {/* Category Selection */}
                            <div className="grid grid-cols-3 gap-4">
                                {(['Paper', 'E-book', 'Audiobook'] as BookType[]).map(t_type => (
                                    <button 
                                        key={t_type}
                                        type="button"
                                        onClick={() => setType(t_type)}
                                        className={`py-6 rounded-[2rem] border-4 font-black text-[10px] uppercase tracking-widest transition-all ${type === t_type ? 'border-accent bg-black text-white shadow-2xl scale-105' : 'border-gray-50 text-gray-400'}`}
                                    >
                                        <div className="flex flex-col items-center gap-2">
                                            {t_type === 'Paper' && <ImageIcon className="w-5 h-5" />}
                                            {t_type === 'E-book' && <FileText className="w-5 h-5" />}
                                            {t_type === 'Audiobook' && <Headphones className="w-5 h-5" />}
                                            {t_type}
                                        </div>
                                    </button>
                                ))}
                            </div>

                            {/* Basic Details */}
                            <div className="space-y-4">
                                <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest px-4">Asset Details</label>
                                <input 
                                    type="text" 
                                    value={title}
                                    onChange={(e) => setTitle(e.target.value)}
                                    placeholder={t('search')} 
                                    className="w-full p-8 bg-gray-50 rounded-[2.5rem] border-4 border-transparent focus:border-accent outline-none font-black text-black text-xl tracking-tighter shadow-inner" 
                                />

                                <div className="flex gap-4">
                                    <div className="flex-[3] relative">
                                        <input 
                                            type="number" 
                                            value={price}
                                            onChange={(e) => setPrice(Number(e.target.value))}
                                            className="w-full p-8 bg-gray-50 rounded-[2.5rem] border-4 border-transparent focus:border-accent outline-none font-black text-black text-4xl text-left shadow-inner" 
                                        />
                                        <div className="absolute right-8 top-1/2 -translate-y-1/2 flex items-center gap-2 text-gray-300 font-black text-xs uppercase">
                                           <Coins className="w-4 h-4" /> {currency}
                                        </div>
                                    </div>
                                    <select 
                                        value={currency}
                                        onChange={(e) => setCurrency(e.target.value)}
                                        className="flex-1 p-6 bg-gray-100 rounded-[2rem] border-none focus:ring-4 focus:ring-accent font-black text-black text-xs uppercase"
                                    >
                                        {ALL_CURRENCIES.map(c => (
                                            <option key={c.code} value={c.code}>{c.code} ({c.name})</option>
                                        ))}
                                    </select>
                                </div>
                            </div>

                            {/* Payout Network Selection */}
                            <div className="space-y-4">
                                <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest px-4 flex items-center gap-2">
                                    <Wallet className="w-3 h-3" /> {isRtl ? 'شبكة استلام الأرباح (رقمي)' : 'Payout Acceptance Network'}
                                </label>
                                <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                                    {WALLETS.map(w => (
                                        <button 
                                            key={w.name}
                                            type="button"
                                            onClick={() => setPayoutNetwork(w.name)}
                                            className={`p-4 rounded-2xl border-2 font-black text-[9px] uppercase tracking-widest transition-all flex flex-col items-center gap-2 ${payoutNetwork === w.name ? 'bg-accent text-black border-accent shadow-lg shadow-accent/20' : 'bg-white border-gray-100 text-gray-400 hover:border-accent/50'}`}
                                        >
                                            <div className="w-8 h-8 bg-black rounded-lg flex items-center justify-center text-accent text-[10px]">{w.symbol.slice(0,2)}</div>
                                            {w.name}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}

                    {step === 2 && (
                        <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
                            <div className="text-center space-y-2">
                                <h3 className="font-black text-xl uppercase italic tracking-tighter">Visual Identity</h3>
                                <p className="text-gray-400 text-[10px] font-black uppercase tracking-widest">{type === 'Paper' ? 'Add condition photos' : 'Add high-quality cover art'}</p>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                {images.map((src, i) => (
                                    <div key={i} className="relative group aspect-square rounded-[2rem] overflow-hidden border-4 border-gray-50 shadow-xl">
                                        <img src={src} className="w-full h-full object-cover" />
                                        <button 
                                            onClick={() => setImages(images.filter((_, idx) => idx !== i))}
                                            className="absolute top-2 right-2 bg-red-500 p-2 rounded-xl text-white opacity-0 group-hover:opacity-100 transition-all"
                                        >
                                            <Trash2 className="w-4 h-4" />
                                        </button>
                                    </div>
                                ))}
                                <button 
                                    onClick={() => imageInputRef.current?.click()}
                                    className="aspect-square rounded-[2.5rem] border-4 border-dashed border-gray-100 flex flex-col items-center justify-center gap-2 hover:border-accent hover:bg-accent/5 transition-all group"
                                >
                                    <div className="p-4 bg-gray-50 rounded-2xl group-hover:bg-accent group-hover:scale-110 transition-all">
                                        <Upload className="w-6 h-6 text-gray-400 group-hover:text-black" />
                                    </div>
                                    <span className="text-[10px] font-black uppercase text-gray-400 tracking-widest">{t('uploadCover')}</span>
                                </button>
                            </div>
                            <input type="file" multiple ref={imageInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
                        </div>
                    )}

                    {step === 3 && (
                        <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
                            <div className="text-center space-y-2">
                                <h3 className="font-black text-xl uppercase italic tracking-tighter">Digital Delivery</h3>
                                <p className="text-gray-400 text-[10px] font-black uppercase tracking-widest">
                                    {type === 'Paper' ? 'Physical book detected. Skip this step.' : 'Upload the source for secure delivery'}
                                </p>
                            </div>

                            {type === 'Paper' ? (
                                <div className="bg-gray-50 p-12 rounded-[3rem] text-center space-y-4 opacity-50 border-4 border-dashed border-gray-100">
                                    <Info className="w-12 h-12 mx-auto text-gray-300" />
                                    <p className="text-[10px] font-black uppercase tracking-widest">No digital file required for paper books.</p>
                                </div>
                            ) : (
                                <div 
                                    onClick={() => fileInputRef.current?.click()}
                                    className={`p-16 rounded-[3rem] border-4 border-dashed transition-all text-center space-y-4 cursor-pointer group ${digitalFile ? 'border-accent bg-accent/5' : 'border-gray-100 hover:border-accent'}`}
                                >
                                    <div className="w-20 h-20 bg-black text-accent rounded-[2rem] flex items-center justify-center mx-auto shadow-2xl group-hover:scale-110 transition-all">
                                        {type === 'E-book' ? <FileText className="w-8 h-8" /> : <Headphones className="w-8 h-8" />}
                                    </div>
                                    <div>
                                        <p className="font-black text-black uppercase tracking-tighter">{digitalFile ? digitalFile.name : t('uploadFile')}</p>
                                        <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest mt-1">MAX 50MB • SECURE ENCRYPTED</p>
                                    </div>
                                    {digitalFile && <div className="flex justify-center"><Check className="text-accent w-6 h-6 stroke-[4px]" /></div>}
                                </div>
                            )}
                            <input 
                                type="file" 
                                ref={fileInputRef} 
                                className="hidden" 
                                accept={type === 'E-book' ? '.pdf,.epub,.mobi' : '.mp3,.wav,.m4a'} 
                                onChange={(e) => setDigitalFile(e.target.files?.[0] || null)} 
                            />
                        </div>
                    )}

                    {step === 4 && (
                        <div className="space-y-8 animate-in fade-in zoom-in">
                            <div className="flex items-center gap-6 bg-white p-6 rounded-[2.5rem] border-4 border-gray-50 shadow-xl">
                                <img src={images[0]} className="w-24 h-32 rounded-2xl object-cover shadow-lg" />
                                <div className="flex-1">
                                    <span className="text-[8px] font-black uppercase tracking-widest bg-black text-accent px-3 py-1 rounded-full">{type}</span>
                                    <h4 className="font-black text-xl text-gray-900 tracking-tighter mt-2">{title}</h4>
                                    <p className="text-accent-hover font-black text-2xl mt-1 tracking-tighter">{price} {currency}</p>
                                    <div className="mt-2 flex items-center gap-2">
                                        <div className="w-4 h-4 bg-black rounded-md flex items-center justify-center text-accent text-[6px] font-black">{payoutNetwork.slice(0,2).toUpperCase()}</div>
                                        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">{isRtl ? 'عبر شبكة:' : 'Via:'} {payoutNetwork}</span>
                                    </div>
                                </div>
                            </div>

                            <div className="p-8 bg-red-50 border-4 border-red-100 rounded-[2.5rem] space-y-4 shadow-xl">
                                <div className="flex items-center gap-3 text-red-600">
                                    <ShieldAlert className="w-6 h-6" />
                                    <h4 className="font-black text-sm uppercase italic tracking-tighter">{isRtl ? 'إقرار المسؤولية الأخلاقية' : 'ETHICAL RESPONSIBILITY PLEDGE'}</h4>
                                </div>
                                <p className="text-[10px] font-bold text-red-900 leading-relaxed uppercase tracking-tight">
                                    {isRtl ? 'أتعهد بأن هذا المحتوى لا يحرض على الكراهية، ولا يحتوي على مواد إباحية، ولا يضر بالمجتمع أو يخالف الآداب العامة. أوافق على أن الإخلال بهذا التعهد يعرض حسابي للحظر النهائي.' : 'I PLEDGE THAT THIS CONTENT DOES NOT INCITE HATE, CONTAIN PORNOGRAPHY, OR HARM SOCIETY. I AGREE THAT BREAKING THIS PLEDGE WILL LEAD TO A PERMANENT BAN.'}
                                </p>
                                <label className="flex items-center gap-3 p-4 bg-white rounded-2xl cursor-pointer hover:bg-red-100 transition-all border border-red-200">
                                    <input 
                                        type="checkbox" 
                                        checked={agreedToEthicalTerms}
                                        onChange={(e) => setAgreedToEthicalTerms(e.target.checked)}
                                        className="w-5 h-5 accent-red-600 rounded" 
                                    />
                                    <span className="text-[10px] font-black text-gray-900 uppercase tracking-widest">{isRtl ? 'أوافق على الشروط الأخلاقية' : 'I AGREE TO ETHICAL TERMS'}</span>
                                </label>
                            </div>

                            <div className="bg-black text-white p-10 rounded-[3rem] space-y-6 relative overflow-hidden shadow-2xl border-t-8 border-accent">
                                <div className="flex justify-between items-center text-[10px] font-black tracking-widest uppercase opacity-40">
                                    <span>System Fee ({activeCommission*100}%)</span>
                                    <span className={activeCommission === 0 ? 'text-accent' : ''}>
                                        {activeCommission === 0 ? 'ELITE WAIVED' : `-${(price * activeCommission).toFixed(2)} ${currency}`}
                                    </span>
                                </div>
                                <div className="flex justify-between items-center pt-8 border-t border-white/10">
                                    <span className="font-black text-sm uppercase tracking-widest italic text-accent">Your Net Earnings</span>
                                    <span className="text-5xl font-black tracking-tighter">
                                        {(price - (price * activeCommission)).toFixed(2)}
                                    </span>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            )}

            {/* Sticky Navigation */}
            <div className="fixed bottom-24 left-0 right-0 p-6 max-w-2xl mx-auto flex gap-4 z-40">
                {step > 1 && !isPublishing && !isScanning && !isCorrecting && !rejectionReason && (
                    <button 
                        onClick={() => setStep(step - 1)}
                        className="flex-1 py-6 rounded-[2rem] font-black text-[10px] uppercase tracking-widest text-gray-400 border-4 border-gray-50 bg-white shadow-xl"
                    >
                        <ChevronLeft className={`w-5 h-5 mx-auto ${isRtl ? 'rotate-180' : ''}`} />
                    </button>
                )}
                <button 
                    disabled={!isStepValid() || isPublishing || isScanning || isCorrecting}
                    onClick={() => step === 4 ? handlePublish() : setStep(step + 1)}
                    className={`flex-[3] py-6 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl transition-all flex items-center justify-center gap-3 ${
                        isStepValid() && !isScanning && !isCorrecting ? 'bg-black text-accent border-4 border-accent/20 active:scale-95' : 'bg-gray-100 text-gray-300 cursor-not-allowed'
                    }`}
                >
                    {isPublishing || isScanning || isCorrecting ? (
                        <div className="w-6 h-6 border-4 border-accent border-t-transparent rounded-full animate-spin"></div>
                    ) : (
                        <> {step === 4 ? t('confirm') : t('next')} <ChevronRight className={`w-4 h-4 ${isRtl ? 'rotate-180' : ''}`} /> </>
                    )}
                </button>
            </div>
        </div>
    );
};

const AppContent: React.FC = () => {
  const [isRegistered, setIsRegistered] = useState<boolean | null>(null);
  const [isBanned, setIsBanned] = useState<boolean>(localStorage.getItem('book_user_banned') === 'true');
  const { t } = useTranslation();

  useEffect(() => {
    const reg = localStorage.getItem('book_user_registered');
    setIsRegistered(!!reg);

    if (reg) {
      MOCK_USER.fullName = localStorage.getItem('book_user_name') || MOCK_USER.fullName;
      MOCK_USER.username = localStorage.getItem('book_user_handle') || MOCK_USER.username;
      MOCK_USER.subscriptionTier = (localStorage.getItem('book_user_tier') as any) || MOCK_USER.subscriptionTier;
    }
  }, []);

  if (isBanned) return <BannedScreen />;
  if (isRegistered === null) return null;
  if (!isRegistered) return <Signup onComplete={() => setIsRegistered(true)} />;

  return (
    <Router>
      <Layout>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/profile" element={<Profile />} />
          <Route path="/user/:userId" element={<Profile />} />
          <Route path="/add" element={<AddListing />} />
          <Route path="/terms" element={<Terms />} />
          <Route path="/privacy" element={<Privacy />} />
          <Route path="/stats" element={<Stats />} />
