const Home: React.FC = () => {
  const { t, isRtl } = useTranslation();
  const [activeFilter, setActiveFilter] = useState('All');
  const [localBooks, setLocalBooks] = useState<Book[]>([]);
  const [reportedIds, setReportedIds] = useState<string[]>([]);

  // UI Modals State
  const [payingForBook, setPayingForBook] = useState<Book | null>(null);
  const [reportingBookId, setReportingBookId] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('book_listings');
    if (saved) {
      setLocalBooks(JSON.parse(saved));
    }
    const reported = JSON.parse(localStorage.getItem('book_reported_items') || '[]');
    setReportedIds(reported);
  }, []);

  const handleReportComplete = (reason: string) => {
    if (reportingBookId) {
      const newReported = [...reportedIds, reportingBookId];
      setReportedIds(newReported);
      localStorage.setItem('book_reported_items', JSON.stringify(newReported));
      setReportingBookId(null);
      alert(isRtl ? 'شكراً لك. تم إرسال البلاغ لمركز الأمن.' : 'Thank you. Report sent to security center.');
    }
  };

  const allBooks = [...localBooks, ...MOCK_BOOKS].filter(b => !reportedIds.includes(b.id));

  const filteredBooks = activeFilter === 'All' 
    ? allBooks 
    : allBooks.filter(b => b.type === activeFilter || b.category === activeFilter);

  return (
    <div className="space-y-10 px-4 py-8 max-w-7xl mx-auto">
      {/* Modals */}
      {payingForBook && <PaymentModal book={payingForBook} onClose={() => setPayingForBook(null)} />}
      {reportingBookId && (
          <ReportModal 
            book={allBooks.find(b => b.id === reportingBookId)!} 
            onClose={() => setReportingBookId(null)} 
            onComplete={handleReportComplete} 
          />
      )}

      <section className="relative h-56 md:h-80 rounded-[3rem] overflow-hidden bg-black flex items-center px-12 shadow-2xl border-4 border-gray-50">
        <div className="absolute inset-0 opacity-50 bg-[url('https://images.unsplash.com/photo-1512820790803-83ca734da794?auto=format&fit=crop&q=80')] bg-cover bg-center"></div>
        <div className={`absolute inset-0 bg-gradient-to-${isRtl ? 'l' : 'r'} from-black via-black/80 to-transparent`}></div>
        <div className={`relative z-10 max-w-xl ${isRtl ? 'text-right pr-4' : 'text-left pl-4'} space-y-4`}>
          <div className="inline-flex items-center gap-2 bg-accent/20 text-accent px-4 py-2 rounded-2xl border border-accent/30 backdrop-blur-sm animate-pulse">
             <Sparkles className="w-4 h-4" />
             <span className="text-[10px] font-black uppercase tracking-widest">Next-Gen Marketplace</span>
          </div>
          <h1 className="text-4xl md:text-7xl font-black text-white leading-[1.1] tracking-tighter italic">
            <span className="text-accent">book</span> HUB
          </h1>
          <p className="text-gray-300 text-sm font-bold uppercase tracking-widest max-w-sm">{t('welcome')}</p>
        </div>
      </section>

      <div className="bg-black/5 p-4 rounded-3xl flex items-center gap-3 border border-black/5">
        <AlertCircle className="w-5 h-5 text-red-500" />
        <p className="text-[9px] font-black text-gray-500 uppercase tracking-widest">{t('ethicalWarning')}</p>
      </div>

      <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar">
        {['All', 'Paper', 'E-book', 'Audiobook', 'Tech', 'Art', 'Business'].map((f) => (
          <button 
            key={f}
            onClick={() => setActiveFilter(f)}
            className={`px-8 py-4 rounded-3xl text-[10px] font-black uppercase tracking-widest whitespace-nowrap transition-all duration-300 ${activeFilter === f ? 'bg-accent text-black scale-105 shadow-2xl shadow-accent/40' : 'bg-white border-2 border-gray-50 text-gray-400 hover:border-accent hover:text-black'}`}
          >
            {f === 'All' ? t('all') : f}
          </button>
        ))}
      </div>

      {filteredBooks.length > 0 ? (
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-8 animate-in fade-in duration-700">
          {filteredBooks.map(book => (
            <BookCard 
                key={book.id} 
                book={book} 
                onReport={(id) => setReportingBookId(id)} 
                onBuy={(b) => setPayingForBook(b)}
            />
          ))}
        </div>
      ) : (
        <div className="py-32 flex flex-col items-center text-center space-y-6">
          <div className="w-24 h-24 bg-gray-50 rounded-[2.5rem] flex items-center justify-center text-gray-200 border-2 border-gray-100 shadow-inner">
             <Inbox className="w-12 h-12" />
          </div>
          <div className="space-y-2">
            <h3 className="text-2xl font-black text-gray-900 uppercase italic tracking-tighter">{t('noBooks')}</h3>
            <p className="text-gray-400 text-[10px] font-black uppercase tracking-widest max-w-xs mx-auto">
