          </div>
          <Link to="/add" className="mt-6 bg-black text-accent px-12 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl shadow-accent/20 hover:scale-110 active:scale-95 transition-all flex items-center gap-3">
            <Plus className="w-5 h-5" /> {t('startSelling')}
          </Link>
        </div>
      )}
