                    <p className="text-gray-400 font-bold text-[10px] uppercase tracking-widest mt-2">{reachedLimit ? 'Limit reached' : `Step ${step} of 5`}</p>
                </div>
                <div className="bg-black p-5 rounded-[2rem] text-center min-w-[110px] border-b-4 border-accent shadow-2xl">
                    <p className="text-[10px] font-black text-gray-400 mb-1">{t('plan')}</p>
                    <p className={`text-lg font-black ${reachedLimit ? 'text-red-500' : 'text-accent'}`}>{currentCount} / {activePlan.limit === Infinity ? '∞' : activePlan.limit}</p>
                </div>
            </div>

            <div className="space-y-8 min-h-[400px]">
                {step === 1 && (
                    <div className="space-y-8 animate-in fade-in">
                        <div className="grid grid-cols-3 gap-4">
                            {(['Paper', 'E-book', 'Audiobook'] as BookType[]).map(t_type => (
                                <button key={t_type} type="button" onClick={() => setType(t_type)} className={`py-6 rounded-[2rem] border-4 font-black text-[10px] uppercase tracking-widest transition-all ${type === t_type ? 'border-accent bg-black text-white shadow-2xl' : 'border-gray-50 text-gray-400'}`}>
                                    <div className="flex flex-col items-center gap-2">
                                        {t_type === 'Paper' && <ImageIcon className="w-5 h-5" />}
                                        {t_type === 'E-book' && <FileText className="w-5 h-5" />}
                                        {t_type === 'Audiobook' && <Headphones className="w-5 h-5" />}
                                        {t_type}
                                    </div>
                                </button>
                            ))}
                        </div>
                        <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} placeholder={t('search')} className="w-full p-8 bg-gray-50 rounded-[2.5rem] border-4 border-transparent focus:border-accent outline-none font-black text-xl shadow-inner" />

                        <div className="p-6 bg-gray-50 rounded-[2rem] border-2 border-gray-100 space-y-4">
                            <div className="flex items-center justify-between px-2">
                                <span className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2"><Gift className="w-4 h-4 text-accent" /> {isRtl ? 'بيع مجاني' : 'Sell for Free'}</span>
                                <button onClick={() => { setIsFree(!isFree); if(!isFree) setPrice(0); }} className={`w-12 h-6 rounded-full transition-all relative ${isFree ? 'bg-accent' : 'bg-gray-200'}`}>
                                    <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${isFree ? 'right-1' : 'left-1'}`}></div>
                                </button>
                            </div>
                            {!isFree && (
                                <div className="flex gap-4">
                                    <input type="number" value={price} onChange={(e) => setPrice(Number(e.target.value))} className="flex-[3] p-8 bg-white rounded-[2rem] outline-none font-black text-black text-4xl shadow-inner" />
                                    <select value={currency} onChange={(e) => setCurrency(e.target.value)} className="flex-1 p-4 bg-white rounded-[2rem] font-black text-xs uppercase shadow-sm">
                                        <optgroup label="Fiat">
