                                            {ALL_CURRENCIES.filter(c => c.type === 'crypto').map(c => <option key={c.code} value={c.code}>{c.code}</option>)}
                                        </optgroup>
                                    </select>
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {step === 4 && type === 'Paper' && (
                    <div className="space-y-8 animate-in zoom-in">
                        <div className="text-center space-y-4">
                            <div className="w-24 h-24 bg-accent/10 rounded-[3rem] flex items-center justify-center mx-auto border-4 border-accent animate-pulse">
                                <Navigation className="w-12 h-12 text-accent" />
