const AddListing = () => {
    const { t, isRtl } = useTranslation();
    const navigate = useNavigate();

    const [step, setStep] = useState(1);
    const [isPublishing, setIsPublishing] = useState(false);
    const [isScanning, setIsScanning] = useState(false);
    const [isCorrecting, setIsCorrecting] = useState(false);
    const [rejectionReason, setRejectionReason] = useState<string | null>(null);
    const [agreedToEthicalTerms, setAgreedToEthicalTerms] = useState(false);

    // Form Data
    const [title, setTitle] = useState('');
    const [type, setType] = useState<BookType>('Paper');
    const [price, setPrice] = useState<number>(0);
    const [isFree, setIsFree] = useState(false);
    const [currency, setCurrency] = useState('USD');
    const [payoutNetwork, setPayoutNetwork] = useState<string>(WALLETS[0].name);
    const [images, setImages] = useState<string[]>([]);
    const [digitalFile, setDigitalFile] = useState<File | null>(null);
    const [location, setLocation] = useState<{lat: number, lng: number} | null>(null);
    const [isLocating, setIsLocating] = useState(false);

    const imageInputRef = useRef<HTMLInputElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const activePlan = SUBSCRIPTION_PLANS.find(p => p.id === MOCK_USER.subscriptionTier) || SUBSCRIPTION_PLANS[0];
    const currentCount = Number(localStorage.getItem('book_user_listings_count') || '0');
    const reachedLimit = currentCount >= activePlan.limit;
    const activeCommission = MOCK_USER.subscriptionTier === 'Enterprise' ? 0 : COMMISSIONS[type];

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files) return;
        const newImages = Array.from(files).map((file: File) => URL.createObjectURL(file));
        setImages(prev => [...prev, ...newImages]);
    };

    const handleGetLocation = () => {
        setIsLocating(true);
        navigator.geolocation.getCurrentPosition(
            (pos) => {
                setLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude });
                setIsLocating(false);
            },
            () => {
                alert(isRtl ? "فشل تحديد الموقع" : "Location failed");
                setIsLocating(false);
            },
            { enableHighAccuracy: true }
        );
    };

    const handlePublish = async () => {
        if (!agreedToEthicalTerms) return;
        setIsScanning(true);
        const moderation = await moderateListingContent({ title, type });

        if (!moderation.isAllowed) {
            setRejectionReason(moderation.reason || t('rejected'));
            setIsScanning(false);
            return;
        }

        setIsScanning(false);
        setIsPublishing(true);

        const newBook: Book = {
            id: Math.random().toString(36).substr(2, 9),
            title,
            author: MOCK_USER.fullName,
            price: isFree ? 0 : price,
            currency,
            coverUrl: images[0] || '',
            sellerId: MOCK_USER.id,
            type,
            category: MOCK_USER.subscriptionTier === 'Pro' ? 'Featured' : 'General',
            description: isFree ? (isRtl ? 'مجاني' : 'Free') : `Payout via ${payoutNetwork}`,
            commissionRate: activeCommission,
            location: location || undefined
        };

        const existing = JSON.parse(localStorage.getItem('book_listings') || '[]');
        localStorage.setItem('book_listings', JSON.stringify([newBook, ...existing]));
        localStorage.setItem('book_user_listings_count', (currentCount + 1).toString());

        setTimeout(() => {
            setIsPublishing(false);
            navigate('/');
        }, 1500);
    };

    const isStepValid = () => {
        if (step === 1) return title.trim() !== '' && (isFree || price >= 0);
        if (step === 2) return images.length > 0;
        if (step === 3) return type === 'Paper' ? true : digitalFile !== null;
        if (step === 4 && type === 'Paper') return location !== null;
        if (step === 5) return agreedToEthicalTerms;
        return true;
    };

    const nextStep = () => {
        if (step === 3 && type !== 'Paper') setStep(5);
        else setStep(step + 1);
    };

    return (
        <div className="p-6 max-w-2xl mx-auto space-y-10 pb-40">
            {/* AI Security Overlay */}
            {(isScanning || isPublishing || isCorrecting || rejectionReason) && (
                <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-8">
                    <div className="w-full max-w-md text-center space-y-8 text-white">
                        {rejectionReason ? (
                            <div className="space-y-6">
                                <h3 className="text-3xl font-black italic uppercase">{t('rejected')}</h3>
                                <p className="text-sm">{rejectionReason}</p>
                                <button onClick={() => setRejectionReason(null)} className="w-full py-5 bg-accent text-black rounded-full font-black uppercase">Try Again</button>
                            </div>
                        ) : (
                            <div className="space-y-6 flex flex-col items-center">
                                <RefreshCw className="w-16 h-16 text-accent animate-spin" />
                                <h3 className="text-2xl font-black italic uppercase">{isScanning ? t('scanning') : 'Publishing...'}</h3>
                            </div>
                        )}
                    </div>
                </div>
            )}

            <div className="flex justify-between items-start">
                <div>
                    <h2 className="text-4xl font-black text-gray-900 uppercase tracking-tighter italic">{isRtl ? 'إضافة كتاب' : 'List Asset'}</h2>
                    <p className="text-gray-400 font-bold text-[10px] uppercase mt-2">Step {step} of 5</p>
                </div>
            </div>

            <div className="space-y-8 min-h-[400px]">
                {step === 1 && (
                    <div className="space-y-8 animate-in fade-in">
                        <div className="grid grid-cols-3 gap-4">
                            {(['Paper', 'E-book', 'Audiobook'] as BookType[]).map(t_type => (
                                <button key={t_type} onClick={() => setType(t_type)} className={`py-6 rounded-[2rem] border-4 font-black text-[10px] uppercase transition-all ${type === t_type ? 'border-accent bg-black text-white' : 'border-gray-50 text-gray-400'}`}>
                                    {t_type}
