                )}

                {step === 3 && type !== 'Paper' && (
                    <div className="space-y-8 animate-in fade-in">
                        <div onClick={() => fileInputRef.current?.click()} className={`p-16 rounded-[3rem] border-4 border-dashed transition-all text-center space-y-4 cursor-pointer ${digitalFile ? 'border-accent bg-accent/5' : 'border-gray-100 hover:border-accent'}`}>
