                        </div>
                        <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => setDigitalFile(e.target.files?.[0] || null)} />
                    </div>
                )}

                {step === 4 && type === 'Paper' && (
                    <div className="space-y-8 animate-in zoom-in text-center">
