                            </button>
                        )}
                    </div>
                )}

                {step === 5 && (
                    <div className="space-y-8 animate-in fade-in">
                        <div className="p-8 bg-red-50 border-4 border-red-100 rounded-[2.5rem] space-y-4">
                            <div className="flex items-center gap-3 text-red-600">
                                <ShieldAlert className="w-6 h-6" />
                                <h4 className="font-black text-sm uppercase italic">{isRtl ? 'إقرار المسؤولية' : 'ETHICAL PLEDGE'}</h4>
                            </div>
                            <label className="flex items-center gap-3 p-4 bg-white rounded-2xl cursor-pointer">
                                <input type="checkbox" checked={agreedToEthicalTerms} onChange={(e) => setAgreedToEthicalTerms(e.target.checked)} className="w-5 h-5 accent-red-600" />
                                <span className="text-[10px] font-black uppercase tracking-widest">{isRtl ? 'أوافق على المعايير الأخلاقية' : 'I AGREE TO ETHICAL TERMS'}</span>
                            </label>
                        </div>
                    </div>
                )}
            </div>

            <div className="fixed bottom-24 left-0 right-0 p-6 max-w-2xl mx-auto flex gap-4">
                {step > 1 && <button onClick={() => setStep(step - 1)} className="flex-1 py-6 rounded-[2rem] bg-white border-4 border-gray-50 font-black uppercase text-[10px]"><ChevronLeft className="w-5 h-5 mx-auto" /></button>}
                <button 
                    disabled={!isStepValid() || isPublishing || isScanning}
                    onClick={() => step === 5 ? handlePublish() : nextStep()}
                    className={`flex-[3] py-6 rounded-[2rem] font-black text-xs uppercase flex items-center justify-center gap-3 shadow-2xl transition-all ${isStepValid() ? 'bg-black text-accent border-4 border-accent/20' : 'bg-gray-100 text-gray-300'}`}
                >
                    {step === 5 ? t('confirm') : t('next')} <ChevronRight className="w-4 h-4" />
                </button>
            </div>
        </div>
    );
};

