const BookCard: React.FC<{ book: Book, onReport: (id: string) => void, onBuy: (book: Book) => void }> = ({ book, onReport, onBuy }) => {
  const { t, isRtl } = useTranslation();
  const navigate = useNavigate();
  const isFree = book.price === 0;
  const isFeatured = book.price > 50 || book.category === 'Featured';

  const getTypeIcon = (type: BookType) => {
    switch(type) {
      case 'Audiobook': return <Headphones className="w-4 h-4" />;
      case 'E-book': return <FileText className="w-4 h-4" />;
      case 'Paper': return <BookOpen className="w-4 h-4" />;
    }
  };

  const handleShare = async (e: React.MouseEvent) => {
    e.stopPropagation();
    const shareData = {
      title: `${book.title} - book`,
      text: `${isRtl ? 'شاهد هذا الكتاب على book:' : 'Check this out on book:'} ${book.title}`,
      url: `${window.location.origin}/#/book/${book.id}`,
    };
    if (navigator.share) await navigator.share(shareData);
    else { navigator.clipboard.writeText(shareData.url); alert(isRtl ? 'تم نسخ الرابط' : 'Link copied'); }
  };

  return (
    <div className={`bg-white rounded-3xl overflow-hidden border transition-all group flex flex-col h-full ${isFeatured ? 'border-accent ring-2 ring-accent shadow-2xl' : 'border-gray-100'}`}>
      <div className="relative aspect-[3/4] overflow-hidden cursor-pointer" onClick={() => navigate(`/book/${book.id}`)}>
        <img src={book.coverUrl || 'https://images.unsplash.com/photo-1543004218-ee1411043384?auto=format&fit=crop&q=80'} alt={book.title} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
        <button onClick={(e) => { e.stopPropagation(); onReport(book.id); }} className="absolute top-3 left-3 bg-red-500/80 p-2 rounded-xl text-white opacity-0 group-hover:opacity-100 transition-all z-20"><Flag className="w-4 h-4" /></button>

        {isFree && (
            <div className="absolute top-3 right-3 bg-accent text-black px-3 py-1.5 rounded-xl text-[10px] font-black animate-pulse z-10 flex items-center gap-1">
                <Gift className="w-3 h-3" /> {isRtl ? 'مجاني' : 'FREE'}
            </div>
        )}

        <div className={`absolute top-3 ${isFree ? 'left-12' : 'right-3'} bg-black/90 text-white px-2.5 py-1.5 rounded-xl text-[10px] font-black shadow-lg`}>
          {isFree ? (isRtl ? "متاح" : "GET") : `${book.price} ${book.currency}`}
        </div>

        {book.location && (
            <div className="absolute bottom-12 right-3 bg-black/80 text-white px-3 py-1.5 rounded-xl text-[8px] font-black flex items-center gap-1">
                <MapPin className="w-3 h-3 text-accent" /> {isRtl ? 'متوفر محلياً' : 'LOCAL PICKUP'}
            </div>
        )}

        <div className="absolute bottom-3 left-3 bg-white/95 text-black px-3 py-1.5 rounded-xl text-[9px] font-black flex items-center gap-2 shadow-xl border border-gray-100">{getTypeIcon(book.type)} {book.type.toUpperCase()}</div>
      </div>
      <div className={`p-5 flex-1 flex flex-col ${isRtl ? 'text-right' : 'text-left'}`}>
        <h4 className="font-black text-gray-900 line-clamp-2 text-sm leading-tight mb-2">{book.title}</h4>
        <div className="mt-auto flex items-center justify-between gap-2">
          <div className="flex gap-2">
            <button onClick={handleShare} className="p-3 bg-gray-50 hover:bg-accent rounded-2xl transition-all group/share"><Share2 className="w-4 h-4 text-gray-400 group-hover/share:text-black" /></button>
          </div>
          <button onClick={() => onBuy(book)} className={`flex-1 text-[10px] font-black py-3 rounded-2xl transition-all shadow-xl ${isFree ? 'bg-accent text-black hover:bg-black hover:text-accent' : 'bg-black text-white hover:bg-accent hover:text-black'}`}>
            {isFree ? (isRtl ? 'احصل عليه مجاناً' : 'Get for Free') : t('buyNow')}
          </button>
        </div>
      </div>
    </div>
  );
};

const Home: React.FC = () => {
  const { t, isRtl } = useTranslation();
  const [activeFilter, setActiveFilter] = useState('All');
  const [localBooks, setLocalBooks] = useState<Book[]>([]);
  const [reportedIds, setReportedIds] = useState<string[]>([]);
  const [payingForBook, setPayingForBook] = useState<Book | null>(null);
  const [reportingBookId, setReportingBookId] = useState<string | null>(null);

  useEffect(() => {
    setLocalBooks(JSON.parse(localStorage.getItem('book_listings') || '[]'));
    setReportedIds(JSON.parse(localStorage.getItem('book_reported_items') || '[]'));
  }, []);

  const handleReportComplete = (reason: string) => {
    if (reportingBookId) {
      const newReported = [...reportedIds, reportingBookId];
      setReportedIds(newReported);
      localStorage.setItem('book_reported_items', JSON.stringify(newReported));
      setReportingBookId(null);
    }
  };

  const allBooks = [...localBooks, ...MOCK_BOOKS].filter(b => !reportedIds.includes(b.id));
  const filteredBooks = activeFilter === 'All' ? allBooks : allBooks.filter(b => b.type === activeFilter || b.category === activeFilter);

  return (
    <div className="space-y-10 px-4 py-8 max-w-7xl mx-auto">
      {payingForBook && <PaymentModal book={payingForBook} onClose={() => setPayingForBook(null)} />}
      <section className="relative h-56 md:h-80 rounded-[3rem] overflow-hidden bg-black flex items-center px-12 shadow-2xl border-4 border-gray-50">
        <div className="absolute inset-0 opacity-50 bg-[url('https://images.unsplash.com/photo-1512820790803-83ca734da794?auto=format&fit=crop&q=80')] bg-cover bg-center"></div>
        <div className="relative z-10 max-w-xl text-left space-y-4">
          <div className="inline-flex items-center gap-2 bg-accent/20 text-accent px-4 py-2 rounded-2xl border border-accent/30 backdrop-blur-sm animate-pulse">
             <Sparkles className="w-4 h-4" /> <span className="text-[10px] font-black uppercase tracking-widest">Global Marketplace</span>
          </div>
          <h1 className="text-4xl md:text-7xl font-black text-white leading-[1.1] tracking-tighter italic"><span className="text-accent">book</span> HUB</h1>
        </div>
      </section>

      <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar">
        {['All', 'Paper', 'E-book', 'Audiobook'].map((f) => (
          <button 
            key={f}
            onClick={() => setActiveFilter(f)}
            className={`px-8 py-4 rounded-3xl text-[10px] font-black uppercase whitespace-nowrap transition-all ${activeFilter === f ? 'bg-accent text-black scale-105' : 'bg-white border-2 border-gray-50 text-gray-400'}`}
          >
            {f === 'All' ? t('all') : f}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-8 animate-in fade-in">
        {filteredBooks.map(book => <BookCard key={book.id} book={book} onReport={(id) => setReportingBookId(id)} onBuy={(b) => setPayingForBook(b)} />)}
      </div>
    </div>
  );
};
export default Home;

