const AddListing = () => {
    const { t, isRtl } = useTranslation();
    const navigate = useNavigate();

    const [step, setStep] = useState(1);
    const [isPublishing, setIsPublishing] = useState(false);
    const [isScanning, setIsScanning] = useState(false);
    const [rejectionReason, setRejectionReason] = useState<string | null>(null);
    const [agreedToEthicalTerms, setAgreedToEthicalTerms] = useState(false);

    // Form Data
    const [title, setTitle] = useState('');
    const [type, setType] = useState<BookType>('Paper');
    const [price, setPrice] = useState<number>(0);
    const [isFree, setIsFree] = useState(false);
    const [currency, setCurrency] = useState('USD');
    const [images, setImages] = useState<string[]>([]);
    const [digitalFile, setDigitalFile] = useState<File | null>(null);
    const [location, setLocation] = useState<{lat: number, lng: number} | null>(null);
    const [isLocating, setIsLocating] = useState(false);

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            setDigitalFile(file);
        }
    };

    const handlePublish = async () => {
        if (!agreedToEthicalTerms) return;
        setIsScanning(true);
        const moderation = await moderateListingContent({ title, type });

        if (!moderation.isAllowed) {
            setRejectionReason(moderation.reason || t('rejected'));
            setIsScanning(false);
            return;
        }

        setIsScanning(false);
        setIsPublishing(true);

        const newId = Math.random().toString(36).substr(2, 9);

        // إذا كان هناك ملف رقمي، نقوم بتحويله لـ Base64 وحفظه
        if (digitalFile) {
            const reader = new FileReader();
            reader.onload = (e) => {
                localStorage.setItem(`book_file_${newId}`, e.target?.result as string);
            };
            reader.readAsDataURL(digitalFile);
        }

        const newBook: Book = {
            id: newId,
            title,
            author: MOCK_USER.fullName,
            price: isFree ? 0 : price,
            currency,
            coverUrl: images[0] || 'https://images.unsplash.com/photo-1543004218-ee1411043384?auto=format&fit=crop&q=80',
            sellerId: MOCK_USER.id,
            type,
            category: 'General',
            description: title,
            commissionRate: COMMISSIONS[type],
            location: location || undefined
        };

        const existing = JSON.parse(localStorage.getItem('book_listings') || '[]');
        localStorage.setItem('book_listings', JSON.stringify([newBook, ...existing]));

        setTimeout(() => {
            setIsPublishing(false);
            navigate('/');
        }, 1500);
    };

    const isStepValid = () => {
        if (step === 1) return title.trim() !== '' && (isFree || price >= 0);
        if (step === 2) return images.length > 0;
        if (step === 3) return type === 'Paper' ? true : digitalFile !== null;
        if (step === 4 && type === 'Paper') return location !== null;
        if (step === 5) return agreedToEthicalTerms;
        return true;
    };

    return (
        <div className="p-6 max-w-2xl mx-auto space-y-10 pb-40">
             {/* AI Scan Overlay */}
             {(isScanning || isPublishing) && (
                <div className="fixed inset-0 z-[100] bg-black/95 flex flex-col items-center justify-center text-white">
                    <RefreshCw className="w-16 h-16 text-accent animate-spin mb-4" />
                    <p className="font-black text-xl italic uppercase">{isScanning ? 'AI Security Scan...' : 'Publishing to Chain...'}</p>
                </div>
            )}

            <div className="flex justify-between items-center">
                <h2 className="text-4xl font-black text-gray-900 uppercase italic tracking-tighter">List Asset</h2>
                <div className="bg-gray-100 px-4 py-2 rounded-2xl font-black text-[10px] text-gray-500">STEP {step}/5</div>
            </div>

            <div className="space-y-8">
                {step === 1 && (
                    <div className="space-y-6 animate-in fade-in">
                        <div className="grid grid-cols-3 gap-4">
                            {(['Paper', 'E-book', 'Audiobook'] as BookType[]).map(t_type => (
                                <button key={t_type} onClick={() => setType(t_type)} className={`py-6 rounded-[2rem] border-4 font-black text-[10px] uppercase transition-all ${type === t_type ? 'border-accent bg-black text-white' : 'border-gray-50 text-gray-400'}`}>{t_type}</button>
                            ))}
                        </div>
                        <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Asset Title..." className="w-full p-8 bg-gray-50 rounded-[2rem] font-black text-xl outline-none" />
                        <div className="p-6 bg-gray-50 rounded-[2rem] flex items-center justify-between">
                            <span className="font-black text-[10px] uppercase text-gray-400">List for Free</span>
                            <button onClick={() => setIsFree(!isFree)} className={`w-12 h-6 rounded-full relative transition-all ${isFree ? 'bg-accent' : 'bg-gray-300'}`}>
                                <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${isFree ? 'right-1' : 'left-1'}`} />
                            </button>
                        </div>
                        {!isFree && (
                            <div className="flex gap-4">
                                <input type="number" value={price} onChange={(e) => setPrice(Number(e.target.value))} placeholder="Price" className="flex-1 p-8 bg-gray-50 rounded-[2rem] font-black text-4xl" />
                                <select value={currency} onChange={(e) => setCurrency(e.target.value)} className="p-6 bg-gray-50 rounded-[2rem] font-black uppercase">
                                    {ALL_CURRENCIES.map(c => <option key={c.code} value={c.code}>{c.code}</option>)}
                                </select>
                            </div>
                        )}
                    </div>
                )}

                {step === 3 && type !== 'Paper' && (
                    <div className="space-y-6 animate-in fade-in text-center">
                        <label className={`block p-20 border-4 border-dashed rounded-[3rem] cursor-pointer transition-all ${digitalFile ? 'border-accent bg-accent/5' : 'border-gray-200 hover:border-accent'}`}>
                            <input type="file" className="hidden" onChange={handleFileUpload} />
                            <FileText className={`w-16 h-16 mx-auto mb-4 ${digitalFile ? 'text-accent' : 'text-gray-300'}`} />
                            <p className="font-black uppercase text-xs">{digitalFile ? digitalFile.name : 'Choose File to Upload'}</p>
                        </label>
                    </div>
                )}

                {step === 4 && type === 'Paper' && (
                    <div className="space-y-6 animate-in zoom-in text-center">
                         <button 
                            onClick={() => {
                                setIsLocating(true);
                                navigator.geolocation.getCurrentPosition(pos => {
                                    setLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude });
                                    setIsLocating(false);
                                });
                            }} 
                            className="w-full py-10 bg-black text-accent rounded-[2rem] font-black uppercase flex flex-col items-center gap-2"
                        >
                            {isLocating ? <RefreshCw className="animate-spin" /> : <MapPin className="w-8 h-8" />}
                            <span>{location ? 'Location Captured' : 'Detect My GPS Location'}</span>
                        </button>
                        {location && <p className="text-[10px] font-mono opacity-50">{location.lat}, {location.lng}</p>}
                    </div>
                )}

                {step === 5 && (
                    <div className="space-y-6 animate-in fade-in text-center">
                        <div className="bg-red-50 p-10 rounded-[2rem] border-2 border-red-100">
                             <p className="font-black text-red-900 uppercase text-xs">Ethical Commitment</p>
                             <p className="text-[10px] text-red-800 mt-2">I confirm this book contains no harmful, illegal, or unethical content.</p>
                             <button onClick={() => setAgreedToEthicalTerms(!agreedToEthicalTerms)} className={`mt-6 p-4 rounded-xl border-2 font-black uppercase text-[10px] transition-all ${agreedToEthicalTerms ? 'bg-black text-white' : 'border-red-200 text-red-300'}`}>I AGREE</button>
                        </div>
                    </div>
                )}
            </div>

            <div className="fixed bottom-24 left-0 right-0 p-6 max-w-2xl mx-auto flex gap-4">
                {step > 1 && <button onClick={() => setStep(step - 1)} className="flex-1 py-6 rounded-[2rem] bg-gray-100 font-black uppercase text-[10px]">Back</button>}
                <button 
                    disabled={!isStepValid()}
                    onClick={() => step === 5 ? handlePublish() : setStep(step + 1)} 
                    className={`flex-[2] py-6 rounded-[2rem] font-black uppercase text-xs shadow-2xl transition-all ${isStepValid() ? 'bg-black text-accent' : 'bg-gray-100 text-gray-300'}`}
                >
                    {step === 5 ? 'Publish Asset' : 'Continue'}
                </button>
            </div>
        </div>
    );
};

