  const getTypeIcon = (type: BookType) => {
    switch(type) {
      case 'Audiobook': return <Headphones className="w-4 h-4" />;
      case 'E-book': return <FileText className="w-4 h-4" />;
      case 'Paper': return <BookOpen className="w-4 h-4" />;
